// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int countGoodRectangles(vector<vector<int>>& rectangles) {
        int result = 0, mx = 0;
        for (const auto& rec : rectangles) {
            int side = min(rec[0], rec[1]);
            if (side > mx) {
                mx = side;
                result = 1;
            } else if (side == mx) {
                ++result;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def countGoodRectangles(self, rectangles):
        """
        :type rectangles: List[List[int]]
        :rtype: int
        """
        result = mx = 0
        for l, w in rectangles:
            side = min(l, w)
            if side > mx:
                result, mx = 1, side
            elif side == mx:
                result += 1
        return result
